      "content": "const projectsService = require('../projects/service');
const { randomUUID } = require('node:crypto');
const sendError = require('../../lib/errors').sendError;

function createTask(projectId) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  const taskId = randomUUID();
  const task = { id: taskId, status: 'todo' };
  project.tasks.push(task);
  return task;
}

function updateTaskStatus(projectId, taskId, status) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
}

function getTasksByStatus(projectId, status) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  if (status && !['todo', 'done'].includes(status)) {
    return [];
  }
  return status ? project.tasks.filter(t => t.status === status) : project.tasks;
}

module.exports = {
  createTask,
  updateTaskStatus,
  getTasksByStatus,
};
